function parseDeepLink(url) {
  const [scheme, rest] = url.split('://');
  const [path, queryString] = rest.split('?');

  const params = {};
  if (queryString) {
    queryString.split('&').forEach(pair => {
      const [key, value] = pair.split('=');
      params[key] = decodeURIComponent(value);
    });
  }

  return { scheme, path, params };
}

const testUrl = 'myapp://products/detail?id=12345&source=email&campaign=summer2024';
const result = parseDeepLink(testUrl);

console.log('スキーム:', result.scheme);
console.log('パス:', result.path);
console.log('パラメータ:', JSON.stringify(result.params));
console.log('商品ID:', result.params && result.params.id);
console.log('流入元:', result.params && result.params.source);
